import{_ as t,o,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"23. Termination Of Employment Notice Of Termination","description":"","frontmatter":{"title":"23. Termination Of Employment Notice Of Termination","eba":"Medical Specialists 2022-2026","topics":["employment","termination"]},"headers":[],"relativePath":"ebas/medical-specialists/employment/23-termination-of-employment-notice-of-termination.md","filePath":"ebas/medical-specialists/employment/23-termination-of-employment-notice-of-termination.md"}'),a={name:"ebas/medical-specialists/employment/23-termination-of-employment-notice-of-termination.md"};function r(m,e,s,c,l,p){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_23-termination-of-employment-notice-of-termination" tabindex="-1">23. Termination Of Employment Notice Of Termination <a class="header-anchor" href="#_23-termination-of-employment-notice-of-termination" aria-label="Permalink to &quot;23. Termination Of Employment Notice Of Termination&quot;">​</a></h1><p><strong>23.1</strong> Either the Health Service or a Doctor may terminate the employment by giving three months’ written notice to the other party, or any other period as agreed between the Health Service and the Doctor, subject to the requirements of the NES.</p><p><strong>23.2</strong> The Health Service may provide a payment in lieu of part or all of the notice period prescribed in subclause 23.1.</p><p><strong>23.3</strong> Subject to financial obligations imposed on the Health Service by any Act, if a Doctor fails to give notice the Health Service shall have the right to withhold monies due to the Doctor with a maximum amount equal to the ordinary time rate of pay for the period of notice.</p><p><strong>23.4</strong> In calculating any payment in lieu of notice, the wages to be used will be those the Doctor would have received in respect of the ordinary time worked during the period of notice had the Doctor’s employment not been terminated.</p><p><strong>23.5</strong> The period of notice in subclause 23.1 does not apply where the conduct of a Doctor justifies instant dismissal, or to those engaged for a fixed term (but not maximum term), specific period of time or for a specified task or tasks.</p><p>Plain language terms: resignation, dismissal.</p>',7)])])}const d=t(a,[["render",r]]);export{h as __pageData,d as default};
